// 3. 셀렉트 박스 다단계 주입 로직
function initRegionSelect() {
    for (let siDo in AreaData) {
        const opt = document.createElement('option');
        opt.value = siDo;
        opt.textContent = siDo;
        step1.appendChild(opt);
    }
}

// 시/도 변경 -> 시/군/구 동적 생성
step1.addEventListener('change', function() {
    step2.innerHTML = '<option value="">시/군/구 선택</option>';
    step3.innerHTML = '<option value="">읍/면/동 선택</option>';
    step3.disabled = true;
    
    if (!this.value) {
        step2.disabled = true;
        return;
    }
    
    const siGunGus = AreaData[this.value];
    for (let siGunGu in siGunGus) {
        const opt = document.createElement('option');
        opt.value = siGunGu;
        opt.textContent = siGunGu;
        step2.appendChild(opt);
    }
    step2.disabled = false;
});

// 시/군/구 변경 -> 읍/면/동 동적 생성
step2.addEventListener('change', function() {
    step3.innerHTML = '<option value="">읍/면/동 선택</option>';
    
    if (!this.value) {
        step3.disabled = true;
        return;
    }
    
    const dongs = AreaData[step1.value][this.value];
    for (let dong in dongs) {
        const opt = document.createElement('option');
        opt.value = dong;
        opt.textContent = dong;
        step3.appendChild(opt);
    }
    step3.disabled = false;
});

// 4. 초단기실황 업데이트 타임(매시 40분) 연산 장치
function getBaseDateTime() {
    const now = new Date();
    
    // 만약 현재 분이 40분 전이라면 기상청 데이터가 적재 안 되었으므로 1시간 전 데이터를 요청함
    if (now.getMinutes() < 40) {
        now.setHours(now.getHours() - 1);
    }
    
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const date = String(now.getDate()).padStart(2, '0');
    const hour = String(now.getHours()).padStart(2, '0');
    
    return {
        baseDate: `${year}${month}${date}`,
        baseTime: `${hour}00`,
        displayTime: `${year}.${month}.${date} ${hour}:00`
    };
}

// 5. 비동기 API 연동 및 날씨 데이터 수신
async function fetchWeather() {
    let nx = DEFAULT_NX;
    let ny = DEFAULT_NY;
    let locationName = "기본 위치 (부산 수영구 부근)";
    
    // 읍면동까지 확실하게 선택되었다면 좌표를 대입함
    if (step1.value && step2.value && step3.value) {
        const coords = AreaData[step1.value][step2.value][step3.value];
        nx = coords.nx;
        ny = coords.ny;
        locationName = `${step1.value} ${step2.value} ${step3.value}`;
    }

    const { baseDate, baseTime, displayTime } = getBaseDateTime();
    
    // 최종 기상청 초단기실황 엔드포인트 URL 조합
    const url = `https://apis.data.go.kr/1360000/VilageFcstInfoService_2.0/getUltraSrtNcst?serviceKey=${SERVICE_KEY}&pageNo=1&numOfRows=1000&dataType=JSON&base_date=${baseDate}&base_time=${baseTime}&nx=${nx}&ny=${ny}`;
    
    // 로딩바 핸들링
    messageBox.classList.remove('hidden');
    messageBox.style.color = '#4a90e2';
    messageBox.textContent = '⚡ 실시간 기상 데이터를 통신 중입니다...';
    resultContainer.classList.add('hidden');

    try {
        const response = await fetch(url);
        if (!response.ok) throw new Error('공공데이터 포털 서버 상태가 불안정합니다.');
        
        const data = await response.json();
        const header = data.response.header;
        
        if (header.resultCode !== "00") {
            throw new Error(`[${header.resultCode}] ${header.resultMsg}`);
        }
        
        const items = data.response.body.items.item;
        displayWeatherResult(items, locationName, displayTime);
        
    } catch (error) {
        messageBox.style.color = '#e74c3c';
        messageBox.textContent = `날씨 정보 반영 실패: ${error.message}`;
    }
}

// 6. 가공된 API 원본 데이터를 UI 요소에 분배 및 가공
function displayWeatherResult(items, locationName, displayTime) {
    messageBox.classList.add('hidden');
    resultContainer.classList.remove('hidden');
    
    document.getElementById('currentLocation').textContent = locationName;
    document.getElementById('currentTime').textContent = `${displayTime} 기준`;
    
    let t1h, reh, rn1, wsd, pty;

    items.forEach(item => {
        switch(item.category) {
            case 'T1H': t1h = item.obsrValue; break; // 기온
            case 'REH': reh = item.obsrValue; break; // 습도
            case 'RN1': rn1 = item.obsrValue; break; // 1시간 강수량
            case 'WSD': wsd = item.obsrValue; break; // 풍속
            case 'PTY': pty = item.obsrValue; break; // 강수형태
        }
    });

    // 화면 텍스트 맵핑
    document.getElementById('txtT1H').textContent = t1h || '--';
    document.getElementById('txtREH').textContent = reh ? `${reh} %` : '-- %';
    document.getElementById('txtRN1').textContent = rn1 ? `${rn1} mm` : '-- mm';
    document.getElementById('txtWSD').textContent = wsd ? `${wsd} m/s` : '-- m/s';

    // 강수 형태 코드 수치 가공 처리
    const ptyState = {
        "0": "☀️ 맑음/구름",
        "1": "🌧️ 비",
        "2": "🌨️ 비/눈",
        "3": "❄️ 눈",
        "5": "🌧️ 빗방울",
        "6": "🌨️ 진눈깨비",
        "7": "❄️ 눈날림"
    };
    document.getElementById('txtPTY').textContent = ptyState[pty] || "☀️ 맑음";
}

// 실행 명령 및 리스너 등록
searchBtn.addEventListener('click', fetchWeather);
initRegionSelect();
